import{_ as t,o as e,c as s,a2 as n}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"Seata 分布式事务","description":"","frontmatter":{"title":"Seata 分布式事务"},"headers":[],"relativePath":"messaging/seata.md","filePath":"messaging/seata.md","lastUpdated":null}'),d={name:"messaging/seata.md"};function i(l,a,o,r,p,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="seata-分布式事务" tabindex="-1">Seata 分布式事务 <a class="header-anchor" href="#seata-分布式事务" aria-label="Permalink to &quot;Seata 分布式事务&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>Seata 是处理跨服务、跨数据库事务一致性问题的分布式事务框架，是国内 Spring Cloud 项目最常见的分布式事务方案。</p><h2 id="同类组件与方案" tabindex="-1">同类组件与方案 <a class="header-anchor" href="#同类组件与方案" aria-label="Permalink to &quot;同类组件与方案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>说明</th></tr></thead><tbody><tr><td><code>Seata</code></td><td>分布式事务框架</td></tr><tr><td><code>RocketMQ Transaction Message</code></td><td>事务消息，详见 <a href="./rocketmq">RocketMQ</a></td></tr><tr><td><code>本地消息表</code></td><td>最终一致性方案</td></tr><tr><td><code>TCC</code></td><td>Try Confirm Cancel 模式</td></tr><tr><td><code>Saga</code></td><td>长事务补偿模式</td></tr></tbody></table><h2 id="重要原则-不要滥用" tabindex="-1">重要原则：不要滥用 <a class="header-anchor" href="#重要原则-不要滥用" aria-label="Permalink to &quot;重要原则：不要滥用&quot;">​</a></h2><p>分布式事务复杂度高、对性能有影响，不能滥用。优先级建议：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>优先本地事务</span></span>
<span class="line"><span>其次消息最终一致性</span></span>
<span class="line"><span>复杂场景再考虑 Seata</span></span></code></pre></div><h2 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h2><p>一个下单流程可能涉及：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建订单</span></span>
<span class="line"><span>扣减库存</span></span>
<span class="line"><span>扣减余额</span></span>
<span class="line"><span>生成支付记录</span></span></code></pre></div><p>如果这些操作分布在多个服务和多个数据库中，就需要考虑分布式事务或最终一致性。如果都在同一个库，用本地事务即可，不需要 Seata。</p><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>大多数场景优先用本地事务或基于 <a href="./">消息队列</a> 的最终一致性。</li><li>确实需要强一致、跨库跨服务时，再引入 Seata。</li></ul>`,14)])])}const b=t(d,[["render",i]]);export{u as __pageData,b as default};
